import { useEffect, useRef } from 'react';
import gsap from 'gsap';

export default function CustomCursor() {
  const cursorRef = useRef(null);
  const cursorRingRef = useRef(null);
  const cursorDotRef = useRef(null);
  const isDark = localStorage.getItem('nexusai_theme') !== 'light';

  useEffect(() => {
    const cursor = cursorRef.current;
    const cursorRing = cursorRingRef.current;
    const cursorDot = cursorDotRef.current;
    
    if (!cursor || !cursorRing || !cursorDot) return;

    // Hide default cursor
    document.body.style.cursor = 'none';
    
    // GSAP quick set for initial position
    gsap.set([cursor, cursorRing, cursorDot], { xPercent: -50, yPercent: -50, opacity: 0 });
    
    // Mouse move animation with smooth following
    const onMouseMove = (e) => {
      // Main cursor dot follows instantly
      gsap.to(cursorDot, {
        duration: 0.05,
        x: e.clientX,
        y: e.clientY,
        ease: "power2.out"
      });
      
      // Outer ring follows with slight delay
      gsap.to(cursorRing, {
        duration: 0.3,
        x: e.clientX,
        y: e.clientY,
        ease: "back.out(0.5)"
      });
      
      // Middle glow follows
      gsap.to(cursor, {
        duration: 0.15,
        x: e.clientX,
        y: e.clientY,
        ease: "power2.out"
      });
    };
    
    // Fade in on mouse enter
    const onMouseEnter = () => {
      gsap.to([cursor, cursorRing, cursorDot], {
        duration: 0.3,
        opacity: 1,
        ease: "power2.out"
      });
    };
    
    // Fade out on mouse leave
    const onMouseLeave = () => {
      gsap.to([cursor, cursorRing, cursorDot], {
        duration: 0.3,
        opacity: 0,
        ease: "power2.out"
      });
    };
    
    // Hover effect for interactive elements
    const onHover = (target) => {
  gsap.to(cursorRing, {
    duration: 0.3,
    scale: 2.5,
    borderColor: `rgba(168,85,247,0.6)`,
    boxShadow: `0 0 30px rgba(168,85,247,0.4)`,
    background: `rgba(168,85,247, 0.1)`,           // ← Glassy background
    backdropFilter: `blur(8px)`,                   // ← Blur for glass effect
    ease: "back.out(0.8)"
  });
  gsap.to(cursor, {
    duration: 0.2,
    scale: 0.5,
    opacity: 0.4,                                 // Thoda transparent
    ease: "power2.out"
  });
  gsap.to(cursorDot, {
    duration: 0.2,
    scale: 0.3,
    ease: "power2.out"
  });
};
    
    const onHoverOut = () => {
      gsap.to(cursorRing, {
        duration: 0.4,
        scale: 1,
        borderColor: `rgba(168,85,247,0.5)`,
        boxShadow: `0 0 15px rgba(168,85,247,0.3)`,
        ease: "elastic.out(1, 0.5)"
      });
      gsap.to(cursor, {
        duration: 0.3,
        scale: 1,
        opacity: 1,
        ease: "power2.out"
      });
      gsap.to(cursorDot, {
        duration: 0.3,
        scale: 1,
        ease: "power2.out"
      });
    };
    
    // Add event listeners
    window.addEventListener('mousemove', onMouseMove);
    document.body.addEventListener('mouseenter', onMouseEnter);
    document.body.addEventListener('mouseleave', onMouseLeave);
    
    // Add hover listeners to all interactive elements
    const interactiveElements = document.querySelectorAll('a, button, .card-hover, .btn-primary, .btn-ghost, .agent-card, .stat-card, .pricing-grid > div, .modules-grid > div');
    
    interactiveElements.forEach(el => {
      el.addEventListener('mouseenter', () => onHover(el));
      el.addEventListener('mouseleave', onHoverOut);
    });
    
    // Dynamic observer for dynamically added elements
    const observer = new MutationObserver(() => {
      const newElements = document.querySelectorAll('a, button, .card-hover, .btn-primary, .btn-ghost, .agent-card, .stat-card, .pricing-grid > div, .modules-grid > div');
      newElements.forEach(el => {
        if (!el._cursorListener) {
          el.addEventListener('mouseenter', () => onHover(el));
          el.addEventListener('mouseleave', onHoverOut);
          el._cursorListener = true;
        }
      });
    });
    
    observer.observe(document.body, { childList: true, subtree: true });
    
    return () => {
      window.removeEventListener('mousemove', onMouseMove);
      document.body.removeEventListener('mouseenter', onMouseEnter);
      document.body.removeEventListener('mouseleave', onMouseLeave);
      observer.disconnect();
      document.body.style.cursor = 'auto';
    };
  }, []);

  // Listen for theme changes to update colors
  useEffect(() => {
    const handleThemeChange = () => {
      const newIsDark = localStorage.getItem('nexusai_theme') !== 'light';
      const ring = cursorRingRef.current;
      if (ring) {
        gsap.to(ring, {
          duration: 0.3,
          borderColor: `rgba(168,85,247, ${newIsDark ? 0.5 : 0.3})`,
          boxShadow: `0 0 15px rgba(168,85,247, ${newIsDark ? 0.4 : 0.2})`,
          ease: "power2.out"
        });
      }
    };
    
    window.addEventListener('storage', handleThemeChange);
    return () => window.removeEventListener('storage', handleThemeChange);
  }, []);

  return (
    <>
      {/* Outer glowing ring */}
      <div
        ref={cursorRingRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '40px',
          height: '40px',
          borderRadius: '50%',
          border: `2px solid rgba(168,85,247,0.6)`,
          boxShadow: '0 0 20px rgba(168,85,247,0.4)',
          pointerEvents: 'none',
          zIndex: 99999,
          willChange: 'transform',
          backdropFilter: 'blur(2px)',
          transition: 'border-color 0.2s, box-shadow 0.2s'
        }}
      />
      {/* Middle glow */}
      <div
        ref={cursorRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '12px',
          height: '12px',
          borderRadius: '50%',
          background: 'radial-gradient(circle, #A855F7, #7C3AED)',
          boxShadow: '0 0 10px #A855F7',
          pointerEvents: 'none',
          zIndex: 99999,
          willChange: 'transform',
          opacity: 0.9
        }}
      />
      {/* Center dot */}
      <div
        ref={cursorDotRef}
        style={{
          position: 'fixed',
          top: 0,
          left: 0,
          width: '4px',
          height: '4px',
          borderRadius: '50%',
          background: '#fff',
          pointerEvents: 'none',
          zIndex: 100000,
          willChange: 'transform'
        }}
      />
    </>
  );
}
